//! skychat_tui — a sovereign Rust terminal client for skychat (the CRDT community chat).
//!
//! Connects to a room's WebSocket (`wss://skychat.forkjoin.ai/room/<id>?did=<nick>`), renders
//! the live message log + presence, and posts what you type. It is a *thin* client: it sends
//! `{type:"post"}` and reads the server's `{type:"sync", snapshot}` / `{type:"presence"}`
//! broadcasts — no local CRDT needed (the edge merges). This is the same room any IRC client
//! (via `wall --bridge`) or agent (via the MCP surface) is in.
//!
//! Architecture: one tokio task drains the WebSocket, one OS thread drains crossterm key events,
//! both feed an mpsc channel; the main loop owns the WS write half + the ratatui terminal and
//! redraws on every event. rustls TLS (sovereign, no openssl).

use std::io;
use std::time::Duration;

use anyhow::{anyhow, Result};
use crossterm::{
    event::{self, Event, KeyCode, KeyEventKind, KeyModifiers},
    execute,
    terminal::{disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
};
use futures::{SinkExt, StreamExt};
use ratatui::{
    prelude::*,
    widgets::{Block, List, ListItem, Paragraph, Wrap},
};
use serde_json::Value;
use tokio::sync::mpsc;
use tokio_tungstenite::{connect_async, tungstenite::Message};

struct App {
    room: String,
    nick: String,
    messages: Vec<(String, String)>,
    members: Vec<String>,
    input: String,
    status: String,
}

enum Ev {
    Server(Value),
    Key(crossterm::event::KeyEvent),
}

fn pct(s: &str) -> String {
    let mut out = String::new();
    for b in s.bytes() {
        match b {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => out.push(b as char),
            _ => out.push_str(&format!("%{:02X}", b)),
        }
    }
    out
}

/// Run the skychat TUI against `base` (http/https URL of the skychat worker), joining `room` as `nick`.
pub async fn run(base: &str, room: &str, nick: &str) -> Result<()> {
    let ws_base = if let Some(rest) = base.strip_prefix("https") {
        format!("wss{rest}")
    } else if let Some(rest) = base.strip_prefix("http") {
        format!("ws{rest}")
    } else {
        base.to_string()
    };
    let url = format!(
        "{}/room/{}?did={}",
        ws_base.trim_end_matches('/'),
        pct(room),
        pct(nick)
    );

    let (ws_stream, _resp) = connect_async(&url)
        .await
        .map_err(|e| anyhow!("connect {url}: {e}"))?;
    let (mut write, mut read) = ws_stream.split();

    let (tx, mut rx) = mpsc::unbounded_channel::<Ev>();

    // WebSocket reader → channel.
    let tx_ws = tx.clone();
    tokio::spawn(async move {
        while let Some(msg) = read.next().await {
            match msg {
                Ok(Message::Text(t)) => {
                    if let Ok(v) = serde_json::from_str::<Value>(&t) {
                        if tx_ws.send(Ev::Server(v)).is_err() {
                            break;
                        }
                    }
                }
                Ok(Message::Close(_)) | Err(_) => break,
                _ => {}
            }
        }
    });

    // Terminal setup (raw mode before the input thread reads stdin).
    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen)?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    // Key reader (blocking) → channel.
    let tx_in = tx.clone();
    std::thread::spawn(move || loop {
        match event::poll(Duration::from_millis(250)) {
            Ok(true) => {
                if let Ok(Event::Key(k)) = event::read() {
                    if k.kind == KeyEventKind::Press && tx_in.send(Ev::Key(k)).is_err() {
                        break;
                    }
                }
            }
            Ok(false) => {}
            Err(_) => break,
        }
    });

    let mut app = App {
        room: room.to_string(),
        nick: nick.to_string(),
        messages: Vec::new(),
        members: vec![nick.to_string()],
        input: String::new(),
        status: format!("connected to {url}"),
    };
    terminal.draw(|f| ui(f, &app))?;

    let result: Result<()> = loop {
        let Some(ev) = rx.recv().await else { break Ok(()) };
        match ev {
            Ev::Server(v) => apply_server(&mut app, &v),
            Ev::Key(k) => match (k.code, k.modifiers) {
                (KeyCode::Char('c'), KeyModifiers::CONTROL) | (KeyCode::Esc, _) => break Ok(()),
                (KeyCode::Enter, _) => {
                    let line = app.input.trim().to_string();
                    app.input.clear();
                    if line == "/quit" || line == "/q" {
                        break Ok(());
                    }
                    if !line.is_empty() {
                        let post = serde_json::json!({
                            "type": "post", "author": app.nick, "content": line, "ts": 0
                        });
                        if write.send(Message::Text(post.to_string())).await.is_err() {
                            app.status = "send failed (disconnected)".to_string();
                        }
                    }
                }
                (KeyCode::Backspace, _) => {
                    app.input.pop();
                }
                (KeyCode::Char(c), _) => app.input.push(c),
                _ => {}
            },
        }
        if terminal.draw(|f| ui(f, &app)).is_err() {
            break Ok(());
        }
    };

    disable_raw_mode().ok();
    execute!(terminal.backend_mut(), LeaveAlternateScreen).ok();
    terminal.show_cursor().ok();
    result
}

/// Bounded, non-interactive one-shot for agents/scripts: optionally post `send`, then print the
/// last `limit` messages (text lines, or JSON with --json) and exit. Pure HTTP over the skychat
/// routes (`POST /room/:id/post`, `GET /room/:id/snapshot`) — no WebSocket, no TUI, no event loop,
/// so it's safe to call from a command line with bounded output.
pub async fn run_oneoff(
    base: &str,
    room: &str,
    nick: &str,
    send: Option<&str>,
    limit: usize,
    json: bool,
) -> Result<()> {
    let room_url = format!("{}/room/{}", base.trim_end_matches('/'), pct(room));
    let client = reqwest::Client::new();

    if let Some(msg) = send {
        if !msg.trim().is_empty() {
            let resp = client
                .post(format!("{room_url}/post"))
                .json(&serde_json::json!({ "author": nick, "content": msg, "ts": 0 }))
                .send()
                .await
                .map_err(|e| anyhow!("post {room_url}/post: {e}"))?;
            if !resp.status().is_success() {
                return Err(anyhow!("skychat post failed: HTTP {}", resp.status()));
            }
        }
    }

    let snap: Value = client
        .get(format!("{room_url}/snapshot"))
        .send()
        .await
        .map_err(|e| anyhow!("get {room_url}/snapshot: {e}"))?
        .json()
        .await
        .unwrap_or(Value::Null);

    let empty: Vec<Value> = Vec::new();
    let msgs = snap.get("messages").and_then(|m| m.as_array()).unwrap_or(&empty);
    let start = msgs.len().saturating_sub(limit);
    let tail = &msgs[start..];

    if json {
        println!("{}", serde_json::to_string(tail).unwrap_or_else(|_| "[]".to_string()));
    } else {
        for m in tail {
            let a = m.get("author").and_then(|x| x.as_str()).unwrap_or("?");
            let c = m.get("content").and_then(|x| x.as_str()).unwrap_or("");
            println!("{a}: {c}");
        }
    }
    Ok(())
}

fn apply_server(app: &mut App, v: &Value) {
    match v.get("type").and_then(|t| t.as_str()) {
        Some("sync") => {
            if let Some(msgs) = v.pointer("/snapshot/messages").and_then(|m| m.as_array()) {
                app.messages = msgs
                    .iter()
                    .filter_map(|m| {
                        Some((
                            m.get("author")?.as_str()?.to_string(),
                            m.get("content")?.as_str()?.to_string(),
                        ))
                    })
                    .collect();
            }
            if let Some(mem) = v.pointer("/snapshot/members").and_then(|m| m.as_array()) {
                app.members = mem.iter().filter_map(|x| x.as_str().map(String::from)).collect();
            }
        }
        Some("presence") => {
            if let Some(on) = v.get("online").and_then(|o| o.as_array()) {
                app.members = on.iter().filter_map(|x| x.as_str().map(String::from)).collect();
            }
        }
        _ => {}
    }
}

fn ui(f: &mut Frame, app: &App) {
    let outer = Layout::vertical([Constraint::Min(1), Constraint::Length(3)]).split(f.area());
    let top = Layout::horizontal([Constraint::Min(10), Constraint::Length(22)]).split(outer[0]);

    let lines: Vec<Line> = app
        .messages
        .iter()
        .map(|(a, c)| {
            Line::from(vec![
                Span::styled(format!("{a}: "), Style::default().fg(Color::Cyan)),
                Span::raw(c.clone()),
            ])
        })
        .collect();
    // Auto-scroll to the newest messages (keep the tail visible).
    let inner_h = top[0].height.saturating_sub(2);
    let scroll_y = (lines.len() as u16).saturating_sub(inner_h);
    let msgs = Paragraph::new(lines)
        .block(Block::bordered().title(format!("#{} — skychat", app.room)))
        .wrap(Wrap { trim: false })
        .scroll((scroll_y, 0));
    f.render_widget(msgs, top[0]);

    let mem: Vec<ListItem> = app.members.iter().map(|m| ListItem::new(m.clone())).collect();
    let members = List::new(mem)
        .block(Block::bordered().title(format!("names ({})", app.members.len())));
    f.render_widget(members, top[1]);

    let input = Paragraph::new(app.input.as_str()).block(
        Block::bordered().title(format!("{} — Enter=send · /quit · Esc", app.nick)),
    );
    f.render_widget(input, outer[1]);
}
